import { createClient } from "https://esm.sh/@supabase/supabase-js@2.45.0";

const IMG_B64 = "";
const ITEM_ID = 2;

Deno.serve(async (_req) => {
  const supabase = createClient(
    Deno.env.get("SUPABASE_URL")!,
    Deno.env.get("SUPABASE_SERVICE_ROLE_KEY")!
  );

  const bin = Uint8Array.from(atob(IMG_B64), (c) => c.charCodeAt(0));
  const { data: machines, error: mErr } = await supabase.from("machines").select("id");
  if (mErr) return new Response(JSON.stringify({ error: mErr.message }), { status: 500 });

  const results: any[] = [];
  for (const m of machines ?? []) {
    const path = `${m.id}/${ITEM_ID}.jpg`;
    const { error: upErr } = await supabase.storage
      .from("reference-photos")
      .upload(path, bin, { upsert: true, contentType: "image/jpeg" });
    if (upErr) { results.push({ machine: m.id, error: upErr.message }); continue; }

    const { error: dbErr } = await supabase
      .from("machine_reference_photos")
      .upsert({ machine_id: m.id, item_id: ITEM_ID, path, updated_at: new Date().toISOString() },
        { onConflict: "machine_id,item_id" });
    results.push({ machine: m.id, ok: !dbErr, dbErr: dbErr?.message });
  }

  return new Response(JSON.stringify({ results }), { headers: { "Content-Type": "application/json" } });
});
